import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2) / truck_speed

    def time_window_penalty(arrival_time, window_start, window_end):
        if arrival_time < window_start:
            return (window_start - arrival_time) * 1
        elif arrival_time > window_end:
            return (arrival_time - window_end) * 10
        else:
            return 0  # within the time window

    def collaborative_factor(truck_location, others_locations):
        sum_distances = 0
        for loc in others_locations:
            sum_distances += calculate_distance(truck_location, loc)
        return sum_distances

    if len(unvisited_customers) < 1:
        return None  # All customers are visited or list is empty

    best_node = None
    min_cost = float('inf')
    other_trucks_pos = [pos for pos in all_truck_pos if not np.array_equal(pos, cur_truck_pos)]

    for idx, customer in enumerate(unvisited_customers):
        travel_distance = calculate_distance(cur_truck_pos, customer)
        predicted_time = current_time + travel_distance
        penalty = time_window_penalty(predicted_time, time_windows[idx][0], time_windows[idx][1])
        collab_bonus = collaborative_factor(customer, other_trucks_pos)

        total_cost = travel_distance + penalty - 0.1 * collab_bonus

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = idx

    return best_node
